+++ b/.github/workflows/squarewright-teach.yml
@@ -0,0 +1,74 @@
+# Squarewright — Teach (TRUSTED phase). ADR-0005 §3: a maintainer replies to a finding with
+# `@squarewright remember: …`; squarewright interprets it into a paste-ready `.review-rules` suggestion and posts
+# it. It NEVER writes a rule file — the human pastes it (no `contents: write`).
+#
+# Security: `issue_comment` / `pull_request_review_comment` are repo-level events that GitHub always runs from the
+# base repo's DEFAULT branch (never a fork's copy), with server-computed fields — so there is no forged-artifact
+# spoofing path (unlike Gather). But this phase HAS the secret and CAN post + spend, so it is gated hard:
+#   1. it must be a PR comment (issue_comment also fires on plain issues — excluded below);
+#   2. a cheap author_association pre-filter, then an AUTHORITATIVE repo-permission check (a COLLABORATOR can be
+#      read-only) — both enforced, plus the PR author is excluded, in `isAuthorizedTeachActor`;
+#   3. the reply body is the one untrusted field — passed via env (never shell-interpolated) and handled as DATA
+#      by the interpreter, only ever surfaced as a suggestion a human pastes.
+name: Squarewright - Teach
+
+on:
+  issue_comment:
+    types: [created]
+  pull_request_review_comment:
+    types: [created]
+
+permissions:
+  contents: read # checkout the trusted default branch for `bun install`
+  pull-requests: write # post the suggestion comment (no `contents: write` — never writes a rule file)
+
+concurrency:
+  group: squarewright-teach-${{ github.event.comment.id }}
+  cancel-in-progress: false
+
+jobs:
+  teach:
+    # Cheap pre-filters (avoid spending Actions minutes / the provider key on comments that can't qualify): must be
+    # a PR comment, from a trusted association, non-bot, and mention us. The AUTHORITATIVE permission + author-exclusion
+    # gate runs in the job (isAuthorizedTeachActor) — association alone does not grant write.
+    if: >-
+      (github.event_name == 'pull_request_review_comment' || github.event.issue.pull_request) &&
+      contains(fromJSON('["OWNER","MEMBER","COLLABORATOR"]'), github.event.comment.author_association) &&
+      !endsWith(github.event.comment.user.login, '[bot]') &&
+      contains(github.event.comment.body, 'squarewright')
+    runs-on: ubuntu-latest
+    timeout-minutes: 10 # bound a stuck model call
+    steps:
+      # No `ref:` — issue_comment/PR-review-comment always resolve to the default-branch tip (trusted base), never
+      # PR-head content. NEVER add a `ref:` here.
+      - name: Checkout base repo (trusted; never PR head)
+        uses: actions/checkout@v4
+
+      - name: Setup Bun
+        uses: oven-sh/setup-bun@v2
+        with:
+          bun-version: 1.3.13
+
+      - name: Install (base repo, trusted)
+        run: bun install --frozen-lockfile
+
+      - name: Interpret the reply and post a suggestion (authorized + confident only)
+        env:
+          GH_TOKEN: ${{ github.token }}
+          # Provider key lives ONLY in this trusted phase. The interpreter defaults to z.ai's free glm-5.2.
+          ZAI_API_KEY: ${{ secrets.ZAI_API_KEY }}
+          # Comment-derived strings pass via env, NEVER interpolated into the shell (injection guard). TEACH_BODY is
+          # the untrusted reply; the rest are GitHub server-computed (trusted).
+          TEACH_REPO: ${{ github.repository }}
+          TEACH_ISSUE: ${{ github.event.issue.number || github.event.pull_request.number }}
+          TEACH_BODY: ${{ github.event.comment.body }}
+          TEACH_ACTOR: ${{ github.event.comment.user.login }}
+          TEACH_ASSOCIATION: ${{ github.event.comment.author_association }}
+          TEACH_IN_REPLY_TO_ID: ${{ github.event.comment.in_reply_to_id }}
+        run: |
+          # Authoritative gate inputs, resolved against the trusted repo (env-quoted, not run-block interpolation):
+          # the actor's real permission level, and the PR author (excluded from teaching their own PR).
+          TEACH_PERMISSION="$(gh api "repos/$TEACH_REPO/collaborators/$TEACH_ACTOR/permission" --jq '.permission' 2>/dev/null || echo none)"
+          TEACH_PR_AUTHOR="$(gh api "repos/$TEACH_REPO/pulls/$TEACH_ISSUE" --jq '.user.login' 2>/dev/null || echo '')"
+          export TEACH_PERMISSION TEACH_PR_AUTHOR
+          bun run src/cli.ts teach
diff --git a/src/assembly/teach-post.test.ts b/src/assembly/teach-post.test.ts
