+# Squarewright — Teach (TRUSTED phase). Scaffolded by `squarewright init`. ADR-0005 §3: a maintainer replies to a
+# finding with `@squarewright remember: …`; squarewright interprets it into a paste-ready `.review-rules`
+# suggestion and posts it as a comment. It NEVER writes a rule file — the human pastes it (no `contents: write`).
+#
+# Security: `issue_comment` / `pull_request_review_comment` always run from the base repo's DEFAULT branch with
+# server-computed fields, so there is no forged-input path. But this phase holds the secret and can post + spend,
+# so it is gated hard: (1) must be a PR comment; (2) a cheap author_association pre-filter here, then an
+# AUTHORITATIVE repo-permission check + PR-author exclusion in the CLI; (3) the reply body is passed via env
+# (never shell-interpolated) and handled as DATA, only ever surfaced as a suggestion a human pastes.
+name: Squarewright - Teach
+
+on:
+  issue_comment:
+    types: [created]
+  pull_request_review_comment:
+    types: [created]
+
+permissions:
+  contents: read
+  pull-requests: write # post the suggestion comment (no `contents: write` — never writes a rule file)
+
+concurrency:
+  group: squarewright-teach-${{ github.event.comment.id }}
+  cancel-in-progress: false
+
+jobs:
+  teach:
+    if: >-
+      (github.event_name == 'pull_request_review_comment' || github.event.issue.pull_request) &&
+      contains(fromJSON('["OWNER","MEMBER","COLLABORATOR"]'), github.event.comment.author_association) &&
+      !endsWith(github.event.comment.user.login, '[bot]') &&
+      contains(github.event.comment.body, 'squarewright')
+    runs-on: ubuntu-latest
+    timeout-minutes: 10
+    steps:
+      # No `ref:` — these events always resolve to the default-branch tip (trusted base). NEVER add a `ref:` here.
+      - name: Checkout base repo (trusted; never PR head)
+        uses: actions/checkout@v4
+
+      # Put the `squarewright` CLI on the runner (same v0.1 distribution gap as the Review workflow).
+      - name: Install Squarewright (pending v0.1 publish — see ROADMAP M4)
+        run: |
+          echo "Install the squarewright CLI here once v0.1 is published (e.g. bunx squarewright@<pinned>)."
+
+      - name: Interpret the reply and post a suggestion (authorized + confident only)
+        env:
+          GH_TOKEN: ${{ github.token }}
+          # Provider key lives ONLY in this trusted phase; the interpreter defaults to z.ai's free glm-5.2.
+          ZAI_API_KEY: ${{ secrets.ZAI_API_KEY }}
+          # Comment-derived strings pass via env, NEVER interpolated into the shell (injection guard).
+          TEACH_REPO: ${{ github.repository }}
+          TEACH_ISSUE: ${{ github.event.issue.number || github.event.pull_request.number }}
+          TEACH_BODY: ${{ github.event.comment.body }}
+          TEACH_ACTOR: ${{ github.event.comment.user.login }}
+          TEACH_ASSOCIATION: ${{ github.event.comment.author_association }}
+          TEACH_IN_REPLY_TO_ID: ${{ github.event.comment.in_reply_to_id }}
+        run: |
+          TEACH_PERMISSION="$(gh api "repos/$TEACH_REPO/collaborators/$TEACH_ACTOR/permission" --jq '.permission' 2>/dev/null || echo none)"
+          TEACH_PR_AUTHOR="$(gh api "repos/$TEACH_REPO/pulls/$TEACH_ISSUE" --jq '.user.login' 2>/dev/null || echo '')"
+          export TEACH_PERMISSION TEACH_PR_AUTHOR
+          squarewright teach
